mapper.sql:
SELECT ROW_NUMBER() OVER(ORDER BY A.SYSJOB_SCHDL_TYCD, A.DGRS_YR, A.DGRS_SMSTR) AS LINE_NO , A.SYSJOB_SCHDL_ID , A.ORG_ID , (SELECT ORGNM FROM TB_LMS_ORG WHERE ORG_ID = A.ORG_ID) AS ORGNM , A.DGRS_YR , A.DGRS_SMSTR
, A.SYSJOB_SCHDL_TYCD
, A.SYSJOB_SCHDL_SYMD , A.SYSJOB_SCHDL_EYMD , A.SYSJOB_SCHDLNM , A.SYSJOB_SCHDL_CMNT , A.USEYN , A.RGTR_ID , A.REG_DTTM , A.MDFR_ID , A.MOD_DTTM
, (SELECT SYSJOB_SCHDL_SYMD FROM TB_LMS_SYSJOB_SCHDL_EXCP WHERE SYSJOB_SCHDL_ID = A.SYSJOB_SCHDL_ID AND SBJCT_ID = #{crsCreCd}) AS EXC_SCH_START_DT , (SELECT SYSJOB_SCHDL_EYMD FROM TB_LMS_SYSJOB_SCHDL_EXCP WHERE SYSJOB_SCHDL_ID = A.SYSJOB_SCHDL_ID AND SBJCT_ID = #{crsCreCd}) AS EXC_SCH_END_DT
, COUNT(1) OVER() AS TOTAL_CNT , CASE WHEN FN_DTTM() BETWEEN A.SYSJOB_SCHDL_SYMD AND A.SYSJOB_SCHDL_EYMD OR A.SYSJOB_SCHDL_SYMD IS NULL THEN 'Y' ELSE 'N' END AS JOB_SCH_PERIOD_YN , CASE WHEN FN_DTTM() >= A.SYSJOB_SCHDL_SYMD THEN 'Y' ELSE 'N' END AS JOB_SCH_START_YN , CASE WHEN FN_DTTM() > A.SYSJOB_SCHDL_EYMD THEN 'Y' ELSE 'N' END AS JOB_SCH_END_YN , CASE WHEN EXISTS ( SELECT 1 FROM TB_LMS_SYSJOB_SCHDL_EXCP X WHERE X.SYSJOB_SCHDL_ID = A.SYSJOB_SCHDL_ID
AND FN_DTTM() BETWEEN X.SYSJOB_SCHDL_SYMD AND X.SYSJOB_SCHDL_EYMD ) THEN 'Y' ELSE 'N' END AS jobSchExcPeriodYn FROM TB_LMS_SYSJOB_SCHDL A JOIN TB_LMS_CMMN_CD B ON A.SYSJOB_SCHDL_TYCD = B.CD AND B.USEYN = 'Y' WHERE A.ORG_ID = #{orgId}
AND A.SYSJOB_SCHDL_ID = #{sysjobSchdlId}
AND A.SYSJOB_SCHDL_TYCD = #{calendarCtgr}
AND A.DGRS_YR = #{haksaYear}
AND A.DGRS_SMSTR = #{haksaTerm}
AND A.USEYN = #{useYn}
AND EXISTS ( SELECT 1 FROM CRS_SMSTR WHERE ORG_ID = A.ORG_ID AND DGRS_YR = A.DGRS_YR AND DGRS_SMSTR = A.DGRS_SMSTR AND CRS_SMSTR_ID = #{termCd} )
AND ( LOWER(A.SYSJOB_SCHDL_TYCD) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.SYSJOB_SCHDLNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
AND A.SYSJOB_SCHDL_TYCD IN
#{item}

mapper.insert:
		/*
             SQL ID : SysJobSchDAO.insert
            	 설  명 : 업무일정 등록
         */
         INSERT INTO TB_LMS_SYSJOB_SCHDL (
         	  SYSJOB_SCHDL_ID
			, ORG_ID
			, DGRS_YR
			, DGRS_SMSTR
			, SYSJOB_SCHDL_TYCD
			, SYSJOB_SCHDL_SYMD
			, SYSJOB_SCHDL_EYMD
			, SYSJOB_SCHDLNM
			, SYSJOB_SCHDL_CMNT
			, USEYN
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
         ) VALUES (
         	  #{jobSchSn}
         	, #{orgId}
         	, #{haksaYear}
         	, #{haksaTerm}
         	, #{calendarCtgr}
         	, #{schStartDt}
         	, #{schEndDt}
         	, #{jobSchNm}
         	, #{schCmnt}
         	, IFNULL(#{useYn}, 'Y')
         	, #{rgtrId}
         	, FN_DTTM()
         	, #{mdfrId}
         	, FN_DTTM()
         )

mapper.update:
		/*
             SQL ID : SysJobSchDAO.update
            	 설  명 : 업무일정 수정
         */
         UPDATE TB_LMS_SYSJOB_SCHDL SET
         	  MDFR_ID = #{mdfrId}
         	, MOD_DTTM = FN_DTTM()

         	, SYSJOB_SCHDL_TYCD = #{calendarCtgr}


         	, ORG_ID = #{orgId}


         	, SYSJOB_SCHDLNM = #{jobSchNm}


         	, DGRS_YR = #{haksaYear}


         	, DGRS_SMSTR = #{haksaTerm}


         	, SYSJOB_SCHDL_SYMD = #{schStartDt}


         	, SYSJOB_SCHDL_EYMD = #{schEndDt}


         	, SYSJOB_SCHDL_CMNT = #{schCmnt}

          WHERE SYSJOB_SCHDL_ID = #{jobSchSn}

mapper.delete:
		/*
             SQL ID : SysJobSchDAO.delete
            	 설  명 : 업무일정 삭제
         */
         DELETE FROM TB_LMS_SYSJOB_SCHDL
          WHERE SYSJOB_SCHDL_ID = #{sysjobSchdlId}

mapper.select:
/* SQL ID : SysJobSchDAO.selectByEndDt 설 명 : 업무일정 마지막 종료일시 정보 조회 */ SELECT ROW_NUMBER() OVER(ORDER BY A.SYSJOB_SCHDL_TYCD, A.DGRS_YR, A.DGRS_SMSTR) AS lineNo , A.SYSJOB_SCHDL_ID AS jobSchSn , A.ORG_ID AS orgId , (SELECT ORGNM FROM TB_LMS_ORG WHERE ORG_ID = A.ORG_ID) AS orgNm , A.DGRS_YR AS haksaYear , A.DGRS_SMSTR AS haksaTerm , IFNULL((SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = A.ORG_ID AND CTGRCD = 'DGRS_SMSTR' AND CD = A.DGRS_SMSTR), '') AS haksaTermNm , A.SYSJOB_SCHDL_TYCD AS calendarCtgr , IFNULL((SELECT CDNM FROM TB_SYS_CODE AS AA WHERE AA.CTGRCD = 'SYSJOB_SCHDL_TYCD' AND AA.CD = A.SYSJOB_SCHDL_TYCD), '') AS calendarCtgrNm , (SELECT CD_OPTN FROM TB_SYS_CODE AS AA WHERE AA.CTGRCD = 'SYSJOB_SCHDL_TYCD' AND AA.CD = A.SYSJOB_SCHDL_TYCD) AS codeOptn , A.SYSJOB_SCHDL_SYMD AS schStartDt , A.SYSJOB_SCHDL_EYMD AS schEndDt , A.SYSJOB_SCHDLNM AS jobSchNm , A.SYSJOB_SCHDL_CMNT AS schCmnt , A.USEYN AS useYn , A.RGTR_ID AS rgtrId , A.FRST_INQ_DTTM AS regDttm , A.MDFR_ID AS mdfrId , A.MOD_DTTM AS modDttm
, (SELECT SYSJOB_SCHDL_SYMD FROM TB_LMS_SYSJOB_SCHDL_EXCP WHERE SYSJOB_SCHDL_ID = A.SYSJOB_SCHDL_ID AND SBJCT_ID = #{crsCreCd}) AS excSchStartDt , (SELECT SYSJOB_SCHDL_EYMD FROM TB_LMS_SYSJOB_SCHDL_EXCP WHERE SYSJOB_SCHDL_ID = A.SYSJOB_SCHDL_ID AND SBJCT_ID = #{crsCreCd}) AS excSchEndDt
, COUNT(1) OVER() AS totalCnt , IF(FN_DTTM() BETWEEN A.SYSJOB_SCHDL_SYMD AND A.SYSJOB_SCHDL_EYMD, 'Y', 'N') AS jobSchPeriodYn , IF(EXISTS( SELECT 1 FROM TB_LMS_SYSJOB_SCHDL_EXCP X WHERE X.SYSJOB_SCHDL_ID = A.SYSJOB_SCHDL_ID AND X.SBJCT_ID = #{crsCreCd} AND FN_DTTM() BETWEEN X.SYSJOB_SCHDL_SYMD AND X.SYSJOB_SCHDL_EYMD ) , 'Y', 'N') AS jobSchExcPeriodYn FROM TB_LMS_SYSJOB_SCHDL AS A LEFT JOIN TB_SYS_CODE AS B ON A.SYSJOB_SCHDL_TYCD = B.CD WHERE A.ORG_ID = #{orgId} AND A.USEYN = 'Y'
AND A.SYSJOB_SCHDL_TYCD = #{calendarCtgr}
ORDER BY A.SYSJOB_SCHDL_EYMD DESC LIMIT 1
